class Solution {
public:
    int totalHammingDistance(vector<int>& nums) {
        long long ans=0; int n=nums.size();
        for(int b=0;b<32;b++){
            int c=0;
            for(int x:nums) c+=(x>>b)&1;
            ans+=1LL*c*(n-c);
        }
        return ans;
    }
};

