int totalHammingDistance(int* nums, int n) {
    long long ans=0;
    for(int b=0;b<32;b++){
        int c=0; for(int i=0;i<n;i++) c+=(nums[i]>>b)&1;
        ans+=(long long)c*(n-c);
    }
    return ans;
}
